// ── Accessors ────────────────────────────────────────────────────────────────

export function getTL2Post(id: string): TL2Post | undefined { return TL2_POSTS.find((p) => p.id === id); }
export function getAllTL2Topics(): TL2Topic[] { return TL2_TOPICS; }
export function getAllTL2SeoMeta() { return TL2_TOPICS.map((t) => ({ id: t.id, locale: t.locale, region: t.region, profession: t.profession, exam: t.exam, title: t.metaTitle, description: t.metaDescription, slug: t.slug })); }
